    elastance_term += mnarx_lung_elastance_coeffs[2]
        * elastance_phi(mnarx_lung_Paw_prev, 2,
            mnarx_lung_elastance_knots, 5)
        * volume;
    elastance_term += mnarx_lung_elastance_coeffs[3]
        * elastance_phi(mnarx_lung_Paw_prev, 3,
            mnarx_lung_elastance_knots, 5)
        * volume;
    elastance_term += mnarx_lung_elastance_coeffs[4]
        * elastance_phi(mnarx_lung_Paw_prev, 4,
            mnarx_lung_elastance_knots, 5)
        * volume;

    /* --- Resistance: Pressure-dependent resistance: Σ bj·Πj,d(Paw)·V̇(t) ---
     * @trace models\lung_mnarx.yaml → blocks.resistance
     * @trace Eq.5, second term (Jayaramaiah et al., 2016)
     */
    real_T resistance_term = 0.0f;
    {
        int32_T i;
        for (i = 0; i < 20; i++) {
            resistance_term += mnarx_lung_resistance_coeffs[i]
                * resistance_phi(mnarx_lung_Paw_prev, i,
                    mnarx_lung_resistance_knots, 20)
                * flow;
        }
    }

    /* --- Offset: Offset pressure term: c·P0(t) ---
     * @trace models\lung_mnarx.yaml → blocks.pressure_offset
     */
